SELECT make_name 
FROM makes 
ORDER BY make_name ASC;

SELECT spec_name, spec_value
FROM engine_specs
WHERE block_id = 1;

SELECT horsepower
  FROM engine_blocks
  ORDER BY horsepower DESC;

SELECT COUNT(*) AS v8_engine_count
FROM engine_blocks
WHERE block_type = 'V8';

SELECT engine_type_name
FROM engine_types
WHERE cylinder_arrangement = 'V';

SELECT COUNT(cylinder_id) AS total_cylinders
FROM cylinders
WHERE block_id = 0;
